/**
 * Specialist: CORS Configuration
 * Checks if CORS is properly configured for server-side applications.
 */

export const checkId = 'cors';
export const name = 'CORS Configured';
export const appliesTo = ['deployable', 'server', 'framework'];

const CORS_DEPS = [
  'cors',
  '@fastify/cors',
  'fastify-cors',
  'koa-cors',
  '@koa/cors',
  'koa2-cors',
  'micro-cors',
  'hono/cors',
  '@elysiajs/cors',
  'itty-cors',
  'express-cors',
  'graphql-cors',
  'apollo-server-cors',
  'cors-anywhere',
];

const SERVER_DEPS = [
  'express',
  'fastify',
  'koa',
  'hono',
  'restify',
  'connect',
  'polka',
  '@nestjs/core',
  'hapi',
  '@hapi/hapi',
  'nitro',
  'nitropack',
  'next',
  'nuxt',
  'astro',
  '@sveltejs/kit',
  '@remix-run/node',
  'solid-start',
  'vite',
  'http-server',
  'serve-static',
];

const META_FRAMEWORKS = ['next', 'nuxt', 'astro', '@sveltejs/kit', 'solid-start', '@remix-run/react', 'gatsby'];

const CORS_PATTERNS = [
  /access-control-allow-origin/i,
  /access-control-allow-methods/i,
  /access-control-allow-headers/i,
  /access-control-allow-credentials/i,
  /access-control-expose-headers/i,
  /access-control-max-age/i,
  /access-control-request/i,
  /require\s*\(\s*['"][^'"]*cors['"]\s*\)/,
  /import\s+.*?['"][^'"]*cors['"]/,
  /from\s+['"][^'"]*cors['"]/,
  /['"]hono\/cors['"]/,
  /['"]@fastify\/cors['"]/,
  /['"]@elysiajs\/cors['"]/,
  /['"]itty-cors['"]/,
  /['"]koa-cors['"]/,
  /['"]@koa\/cors['"]/,
  /enableCors/i,
  /allowedOrigins?/i,
  /allowOrigin/i,
  /corsOrigins?/i,
  /cors\s*:\s*(true|\{)/i,
  /cors\s*\(/i,
  /use\s*\(\s*cors/i,
  /register\s*\([^)]*cors/i,
  /corsHandler/i,
  /handleCors/i,
  /withCors/i,
  /setHeader\s*\(\s*['"]Access-Control/i,
  /headers\s*\(\s*\)\s*\{[^}]*access-control/i,
];

function hasAnyDep(deps, list) {
  if (!deps) return false;
  const keys = Object.keys(deps);
  return list.some((d) => keys.includes(d));
}

function findDep(deps, list) {
  if (!deps) return null;
  const keys = Object.keys(deps);
  return list.find((d) => keys.includes(d)) || null;
}

function isLibraryOrToolSource(packageJson, tree) {
  if (!packageJson) return false;
  const pj = packageJson;
  const name = pj.name || '';
  const scripts = pj.scripts || {};
  const deps = { ...pj.dependencies, ...pj.devDependencies };
  const isPrivate = pj.private === true;
  const hasMain = !!(pj.main || pj.module || pj.exports || pj.types || pj.typings);
  const hasPeerDeps = !!(pj.peerDependencies && Object.keys(pj.peerDependencies).length > 0);
  const workspacePkgs = tree.filter((p) => /\/package\.json$/.test(p) && p !== 'package.json');
  const hasStartOrServe = !!(scripts.start || scripts.serve || scripts['start:prod']);
  const hasServerDep = hasAnyDep(deps, SERVER_DEPS);
  const hasAppsDir = tree.some((p) => /^apps\/[^/]+\//.test(p));
  const hasPackagesDir = tree.some((p) => /^packages\/[^/]+\//.test(p));
  const hasServicesDir = tree.some((p) => /^services\/[^/]+\//.test(p));

  // Known build/test tools by exact name
  const toolNames = new Set([
    'webpack', 'rollup', 'esbuild', 'parcel', 'babel', 'gulp', 'grunt',
    'tsup', 'unbuild', 'turbo', 'turborepo', 'lerna', 'nx',
    'vitest', 'jest', 'mocha', 'ava', 'c8', 'nyc',
    'eslint', 'prettier', 'biome', 'swc', 'oxc',
  ]);
  if (toolNames.has(name)) return true;

  // Library signals
  if (hasPeerDeps && !hasStartOrServe) return true;
  if (hasMain && !hasStartOrServe && !hasServerDep) return true;

  // Framework/tool monorepo source (packages only, no apps/services)
  if (isPrivate && hasPackagesDir && !hasAppsDir && !hasServicesDir && workspacePkgs.length >= 3) {
    return true;
  }

  // Keyword-based library/tool
  const keywords = pj.keywords || [];
  const libKeywords = ['library', 'framework', 'plugin', 'tool', 'sdk', 'utils', 'helpers', 'toolkit', 'module'];
  if (keywords.some((k) => libKeywords.includes(k.toLowerCase())) && !hasStartOrServe) {
    return true;
  }

  return false;
}

function isTutorialRepo(packageJson, tree) {
  if (!packageJson) return false;
  const name = packageJson.name || '';
  if (/(learn|tutorial|example|starter|template|course|demo)/i.test(name)) return true;

  const workspacePkgs = tree.filter((p) => /\/package\.json$/.test(p) && p !== 'package.json');
  const scripts = packageJson.scripts || {};
  const deps = { ...packageJson.dependencies, ...packageJson.devDependencies };
  const hasServerDep = hasAnyDep(deps, SERVER_DEPS);
  const hasStart = !!(scripts.start || scripts.serve);

  if (workspacePkgs.length > 3 && !hasStart && !hasServerDep && packageJson.private === true) {
    return true;
  }
  return false;
}

export async function check(context) {
  const { tree, files, packageJson, repoType } = context;

  try {
    // --- Repo-type quick exits ---
    if (repoType === 'empty') {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Empty repo — CORS not applicable', findings: [] };
    }

    const relevantFiles = tree.filter((p) =>
      /\.(js|ts|mjs|cjs|jsx|tsx|mts|cts|json|toml|yaml|yml)$/.test(p)
    );
    if (relevantFiles.length === 0) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'No relevant source files — CORS not applicable', findings: [] };
    }

    // --- Root dependency check ---
    const rootDeps = {
      ...packageJson?.dependencies,
      ...packageJson?.devDependencies,
      ...packageJson?.peerDependencies,
    };
    const rootCorsDep = findDep(rootDeps, CORS_DEPS);
    if (rootCorsDep) {
      return { checkId, status: 'pass', confidence: 'high', message: `CORS dependency found (${rootCorsDep})`, findings: [] };
    }

    // --- Monorepo workspace dependency check ---
    const isMonorepo = !!(
      packageJson?.workspaces ||
      tree.some((p) => /^pnpm-workspace\.yaml$/.test(p)) ||
      tree.some((p) => /^turbo\.json$/.test(p)) ||
      tree.some((p) => /^lerna\.json$/.test(p))
    );

    if (isMonorepo) {
      const pkgPaths = tree
        .filter((p) => /\/package\.json$/.test(p) && p !== 'package.json')
        .slice(0, 20);

      for (const pkgPath of pkgPaths) {
        const content = await files.get(pkgPath);
        if (!content) continue;
        try {
          const pj = JSON.parse(content);
          const deps = { ...pj.dependencies, ...pj.devDependencies, ...pj.peerDependencies };
          const dep = findDep(deps, CORS_DEPS);
          if (dep) {
            return {
              checkId,
              status: 'pass',
              confidence: 'high',
              message: `CORS dependency found in workspace ${pkgPath} (${dep})`,
              findings: [{ file: pkgPath, issue: 'CORS dependency detected' }],
            };
          }
        } catch (e) {
          console.error(`[${checkId}] JSON parse error in ${pkgPath}:`, e);
        }
      }
    }

    // --- Library / tool / framework-source detection ---
    if (isLibraryOrToolSource(packageJson, tree)) {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: 'Library, tool, or framework source — CORS not applicable',
        findings: [],
      };
    }

    if (isTutorialRepo(packageJson, tree)) {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: 'Tutorial or example repo — CORS not applicable',
        findings: [],
      };
    }

    // --- Meta-framework static-site detection ---
    const hasMetaFramework = META_FRAMEWORKS.some((d) => rootDeps[d]);
    const hasExplicitApiRoutes = tree.some((p) =>
      /\/(pages\/api|app\/api|src\/app\/api|src\/pages\/api|server\/api|server\/routes|api\/routes)\//.test(p)
    );
    const hasServerDep = hasAnyDep(rootDeps, SERVER_DEPS);

    if (hasMetaFramework && !hasExplicitApiRoutes && !hasServerDep) {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: 'Meta-framework site without API routes — CORS not applicable',
        findings: [],
      };
    }

    // --- Scan candidate files for CORS patterns ---
    const candidates = [];
    for (const p of tree) {
      if (/node_modules|\/\.|dist\/|build\/|coverage\/|\.next\/|out\/|\.tmp\/|test|spec|__tests__|\.test\.|\.spec\.|fixture|mock/i.test(p)) continue;
      if (!/\.(js|ts|mjs|cjs|jsx|tsx|mts|cts|json|toml|yaml|yml)$/.test(p)) continue;

      let score = 0;
      if (/\.(config|rc)\.(js|ts|mjs|cjs)$/.test(p)) score += 100;
      if (/(next|nuxt|astro|vite|nitro|wrangler|remix|hono|esbuild|rollup|webpack)\.config/.test(p)) score += 90;
      if (/^(server|app|index|main|listen)\.(js|ts|mjs|cjs)$/.test(p)) score += 80;
      if (/\/(server|app|index|main|listen)\.(js|ts|mjs|cjs)$/.test(p)) score += 70;
      if (/\/(api|routes|controllers|handlers|middleware|plugins)\//.test(p)) score += 60;
      if (/\.route\.(js|ts|mjs|cjs)$/.test(p)) score += 50;
      if (/\.(js|ts|mjs|cjs|jsx|tsx)$/.test(p)) score += 10;
      if (/\.(toml|yaml|yml|json)$/.test(p)) score += 5;

      if (score > 0) candidates.push({ path: p, score });
    }

    candidates.sort((a, b) => b.score - a.score);
    const scanFiles = candidates.slice(0, 25);

    for (const { path: filePath } of scanFiles) {
      const content = await files.get(filePath);
      if (!content) continue;

      for (const pattern of CORS_PATTERNS) {
        if (pattern.test(content)) {
          return {
            checkId,
            status: 'pass',
            confidence: 'high',
            message: `CORS configuration found in ${filePath}`,
            findings: [{ file: filePath, issue: 'CORS detected' }],
          };
        }
      }

      // Loose CORS mention in config files (headers, TOML, YAML)
      if (/\.(json|toml|yaml|yml)$/.test(filePath) && /cors/i.test(content) && /access-control/i.test(content)) {
        return {
          checkId,
          status: 'pass',
          confidence: 'high',
          message: `CORS configuration found in ${filePath}`,
          findings: [{ file: filePath, issue: 'CORS detected in config' }],
        };
      }
    }

    // --- Determine whether a server / API runtime actually exists ---
    const serverFilePaths = tree
      .filter(
        (p) =>
          (/^(server|app|index|main)\.(js|ts|mjs|cjs)$/.test(p) ||
            /\/(server|app|index|main)\.(js|ts|mjs|cjs)$/.test(p)) &&
          !/node_modules/.test(p)
      )
      .slice(0, 5);

    let serverImportsFound = false;
    for (const sfp of serverFilePaths) {
